;-------------------------------------------------------------------------------
*event_1
;[exp] party.lastIsMove && random < 0.3

@monster pos=3 name=マッドウイング
@callbattle gameover=true
@eval exp='tf.temp = game.storeItemSomewhere(%[itemData: o.マッドウイングの羽],,, true)'
[if exp='tf.temp !== void']
	@notice text=&'"<y>" + tf.temp.displayName + "<w> got <p>Madwing Feather<w>!"'
	@delevent
[endif]

[eventoff]
